758: func (s *EtcdServer) run() {
759: 	lg := s.Logger()
760: 
761: 	sn, err := s.r.raftStorage.Snapshot()
762: 	if err != nil {
763: 		lg.Panic("failed to get snapshot from Raft storage", zap.Error(err))
764: 	}
765: 
766: 	// asynchronously accept toApply packets, dispatch progress in-order
767: 	sched := schedule.NewFIFOScheduler(lg)
768: 
769: 	rh := &raftReadyHandler{
770: 		getLead:    func() (lead uint64) { return s.getLead() },
771: 		updateLead: func(lead uint64) { s.setLead(lead) },
772: 		updateLeadership: func(newLeader bool) {
773: 			if !s.isLeader() {
774: 				if s.lessor != nil {
775: 					s.lessor.Demote()
776: 				}
777: 				if s.compactor != nil {
778: 					s.compactor.Pause()
779: 				}
780: 			} else {
781: 				if newLeader {
782: 					t := time.Now()
783: 					s.leadTimeMu.Lock()
784: 					s.leadElectedTime = t
785: 					s.leadTimeMu.Unlock()
786: 				}
787: 				if s.compactor != nil {
788: 					s.compactor.Resume()
789: 				}
790: 			}
791: 			if newLeader {
792: 				s.leaderChanged.Notify()
793: 			}
794: 			// TODO: remove the nil checking
795: 			// current test utility does not provide the stats
796: 			if s.stats != nil {
797: 				s.stats.BecomeLeader()
798: 			}
799: 		},
800: 		updateCommittedIndex: func(ci uint64) {
801: 			cci := s.getCommittedIndex()
802: 			if ci > cci {
803: 				s.setCommittedIndex(ci)
804: 			}
805: 		},
806: 	}
807: 	s.r.start(rh)
808: 
809: 	ep := etcdProgress{
810: 		confState:           sn.Metadata.ConfState,
811: 		diskSnapshotIndex:   sn.Metadata.Index,
812: 		memorySnapshotIndex: sn.Metadata.Index,
813: 		appliedt:            sn.Metadata.Term,
814: 		appliedi:            sn.Metadata.Index,
815: 	}
816: 
817: 	defer func() {
818: 		s.wgMu.Lock() // block concurrent waitgroup adds in GoAttach while stopping
819: 		close(s.stopping)
820: 		s.wgMu.Unlock()
821: 		s.cancel()
822: 		sched.Stop()
823: 
824: 		// wait for goroutines before closing raft so wal stays open
825: 		s.wg.Wait()
826: 
